var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"SIGMA_RAS_OPR_NULL","text":{"KOREA":"다이브 성공! 목적지에 도착했어요, 승객 여러분!","JPN":"ダイブ成功！　乗客の皆さん、目的地に到着しました！","ENG":"Dive success! We've reached the destination, ladies and gentlemen.","TWN":"躍入成功！各位乘客，我們抵達目的地囉！"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_OPR_NULL","face":"UNIT_LAUGH"},"R":null}},"sfx":"FX_CUTSCEN_BEEP2"},{"id":"L3_1","type":"dialog","speaker":"SIGMA_RAS_OPR_NULL","text":{"KOREA":"현지 날씨는 흐림, CSE 레벨은 4 입니다! 주의가 필요해요~","JPN":"現在の天気は曇り、CSEレベルは4です！　注意が必要で～す。","ENG":"The current weather is cloudy, with the CSE level of 4. Please proceed with due caution.","TWN":"當地天氣多雲，CSE等級為4！請大家注意～"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_OPR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"……잠깐만, 레벨이 4 라고?","JPN":"……ちょっと待って、レベル4？","ENG":"…Hang on, level 4?","TWN":"……等等，你說等級是4？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L9_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"그럼 4종 침식체도 나타날 수 있다는 뜻이잖아?","JPN":"ってことは、第4種侵食体も現れるってことだよね？","ENG":"That means we could see C.O.s up to Category 4's here, correct?","TWN":"那不就是會出現4類侵蝕體的意思嗎？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"그냥 얌전히 부사장님이 시킨 일이나 할 걸 그랬나.","JPN":"大人しく副社長に頼まれた雑務でもしておけばよかった。","ENG":"Maybe I should have just stuck with the Vice President's job.","TWN":"不是說要乖乖地執行副總交代的事嗎？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"CSE 레벨 4라니, 얼마나 고심도까지 다이브한 거죠?","JPN":"CSEレベル4だなんて、どれほど高深度までダイブしたのですか？","ENG":"CSE Level 4? How deep did we dive?","TWN":"CSE等級竟然是4，這是躍入到多高深度？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"이대로라면 진입하기에는 너무 위험해요.","JPN":"このまま進むのは非常に危険です。","ENG":"It will be too dangerous to proceed like this.","TWN":"這樣下去進入會有危險，"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"……아무래도 제가 경솔했다는 생각이 드네요.","JPN":"……どうやら私が軽率だったようですね。","ENG":"…I'm beginning to think that I've been rather rash.","TWN":"……都怪我太草率，"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"돌아가서 관리국의 정식 지원을 요청하는 게 좋겠어요.","JPN":"戻って管理局に正式支援を要請したほうがいいでしょう。","ENG":"We should go back and officially ask for Administration support.","TWN":"還是回去向管理局請求正式支援吧！"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"……하지만 시간을 끌었다간 선배가 위험해질지도 몰라.","JPN":"……でも、時間をかけると先輩が危ないかもしれない。","ENG":"…But if we delay any further, Shiyoon could be in danger.","TWN":"……但時間拖越久前輩就越危險，"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"일개 용병 구출하는 일에 관리국이 나서 줄지도 알 수 없고.","JPN":"たかが傭兵一人を救出するために管理局が動いてくれるかもわからないし。","ENG":"Plus, I'm not sure the Administration will get involved with rescuing some random mercenary.","TWN":"而且也不確定管理局是否會因為區區一個傭兵而出手。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…….","TWN":"……"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"회장 말대로 위험한 건 사실이야. 나머진 우리한테 맡기고 지금이라도 돌아가.","JPN":"会長の言うとおり危険なのは事実だよ。あとは私たちに任せて、今からでも戻ったほうがいいよ。","ENG":"But you're right. This is dangerous. You can go back now and leave the rest to us.","TWN":"確實像會長說的會有危險，所以其他就交給我們，你們先回去吧！"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"여기까지 같이 와 준 것만으로도 고마우니까.","JPN":"ここまで一緒に来てくれただけでもありがたいから。","ENG":"I'm grateful that you came this far.","TWN":"你們願意陪我們走到這裡我已經覺得很感謝。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"선배는 나와 서윤이 어떻게든 찾아볼게.","JPN":"先輩は私とシズカで何とかして探してみる。","ENG":"Seo Yoon and I will find Shiyoon somehow.","TWN":"我和徐芸無論如何會救出前輩的！"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L24_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"은근슬쩍 나까지 끼워 넣는 걸 보니 능청이 늘었는걸?","JPN":"さりげなく私を巻き込むのはさすがね。ずいぶん図々しくなったものだわ。","ENG":"Think you're pretty smooth, including me like that, huh?","TWN":"竟然默默地把我算進去，看來你挖坑的技巧進步不少呢？！"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"나도 4종 같은 괴물들이랑 싸우는 건 사양인데.","JPN":"私も第4種みたいな化け物と戦うのはごめんなんだけど。","ENG":"Personally, I'd rather not fight Category 4's either.","TWN":"我也沒有要和4類侵蝕體的意思。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"네 성격상 공짜로 그런 일을 맡지는 않았을 테니까. 나도 부담 없이 부려먹을 생각이야.","JPN":"あなたの性格上、タダでそんな仕事を引き受けるわけはないから。私も気軽にこき使うつもりだよ。","ENG":"I know you'd never take on something like this if you weren't getting paid. So I'm going to take advantage of you without a guilty conscience.","TWN":"我知道你不是會無酬做這種事的人，那我當然就不客氣囉！"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"어때? 내 말에 틀린 점이라도 있어?","JPN":"どう？　私の言うことに間違いでもある？","ENG":"Well? Am I mistaken?","TWN":"怎樣？我有說錯嗎？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"……맞는 말이긴 한데 너한테 들으니까 기분이 좀 나쁘네.","JPN":"……そのとおりだけど、ミナに言われるとちょっとムカつくね。","ENG":"…No, but it's kind of funny hearing that from you.","TWN":"……是沒錯，只是從你口裡聽到這些話感覺滿差的。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"내 속옷까지 털어가겠다던 펜릴 소대 돈귀신이 누구셨더라?","JPN":"身に着けたもの全部没収するとか言っていた、フェンリル小隊一の金の亡者さんは誰だっけ？","ENG":"What happened to that money-grubber who wanted to sell everything down to my last sock?","TWN":"也不想想連我的內衣都要扒走的芬里爾小隊錢嫂是誰？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L30_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"글쎄, 누구였지? 난 잘 기억이 안 나는데?","JPN":"さあ、誰だろう？　思い出せないんだけど？","ENG":"What money-grubber? I'm not sure what you're talking about.","TWN":"有這種事？是誰？我怎麼沒印象？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L31_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…….","TWN":"……"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L33_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"어쨌든 다들 돌아가. 시그마가 안전하게 데려다 줄 거야.","JPN":"とにかくみんな戻って。シグマが安全に連れていってくれるから。","ENG":"In any case, the rest of you can go back. Sigma will get you home safely.","TWN":"總之大家就先回去吧！西格瑪會把你們安全地載回去的！"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"돌아가라니, 무슨 소리야!","JPN":"戻れだなんて、何言ってんの！","ENG":"What do you mean, go back?!","TWN":"誰要回去！不許你胡說！"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"편입생 듀오가 가는데 이 나이엘님더러 도망치라고?","JPN":"編入生デュオが行くのに、このナイエル様に逃げろですって？","ENG":"You can't expect the great Naielle to run when the two transfer students are staying!","TWN":"憑什麼插班生二人組說要去，卻叫我不戰而逃？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"우리는 우리대로 낙오자 후보생이랑 알렌 선생을 찾으러 온 거야.","JPN":"私たちは私たちの力で落ちこぼれ候補生とアレン先生を探しに来たの。","ENG":"We're here to find Allen Birmingham and that loser student!","TWN":"我們是自己要來找艾倫老師的！"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"그리고 수색이라면 사람이 많은 편이 절대적으로 유리하지. 너희 둘만으로 이 넓은 데를 돌아다니려면 며칠이 걸려도 모자랄걸?","JPN":"それに捜索なら人数が多いほうが絶対に有利でしょ。\\nあんたたち二人だけでこの広い場所を探すには何日あっても足りないわ。","ENG":"Besides, it always helps to have extra people when you're searching for someone. It'll take days or even weeks for you two to scour this place on your own!","TWN":"而且搜尋這種事，當然是人越多越好囉！這地方那麼大，光憑你們兩個人是要找到何年何月？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"나, 나이엘이 사리에 맞는 말을 했어! 심지어 최면에 걸려 있는데!","JPN":"ナ、ナイエルが正しいことを言ってる！　しかも催眠にかかっているのに！","ENG":"N-Naielle actually said something that makes sense! And she's under hypnosis!","TWN":"這次我覺得奈爾說得很有道理！雖然她是在被催眠的狀態下說的！"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"……경이로운 광경이군요. 역시 사람은 성장하는 동물이에요.","JPN":"……驚異的な光景です。やはり人は成長するものなのですね。","ENG":"How truly amazing indeed. People do improve after all.","TWN":"……真是令人震驚！人類果然是會成長的動物。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L43_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"대체 날 뭘로 보는 거야? 난 나이엘 블루스틸이라고!","JPN":"私を誰だと思ってるの？　私はナイエル・ブルースチールよ！","ENG":"What do you take me for? I'm Naielle Bluesteel!","TWN":"你們到底把我當成什麼啦！我可是奈爾 布魯斯提爾欸！"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"아카데미 최강의 2종 슬레이어이자……","JPN":"アカデミー最強の第2種スレイヤーであり……","ENG":"I'm the Academy's best Category 2 Slayer and…","TWN":"是學院最強的2類屠戮者……"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"네, 네. 안타는 쓰레기라고요. 알겠습니다.","JPN":"はいはい、燃えないゴミですね。わかってますよ。","ENG":"Yeah, yeah. the upcyclable garbage. We get it already.","TWN":"知道啦知道啦，而且還是不可燃垃圾。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"……자, 잘 알고 있네.","JPN":"……よ、よくわかってるじゃない。","ENG":"S-so you know…","TWN":"知……知道就好！"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…….","TWN":"……"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"하지만 나이엘 학생의 말이 옳아요.","JPN":"確かにナイエルさんが正しいです。","ENG":"But Naielle is right this time.","TWN":"不過奈爾同學說的沒錯。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"미나 학생과 서윤 양은 목숨을 걸고 우릴 위해 싸워 줬는데, 저는 사사로운 안위를 우선시했습니다.","JPN":"ミナさんとシズカさんは命をかけて私たちのために戦ってくれたのに、\\n私は自分の安全を優先してしまいました。","ENG":"You two put your lives at risk to fight for us, but I selfishly put my own safety first.","TWN":"米娜同學和徐芸可以為我們拼命奮戰，我卻以個人的安危為優先考量。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"회장 잘못이 아니야. 학생들의 안전을 우선하는 건 당연하잖아.","JPN":"会長は間違ってないよ。生徒たちの安全を優先するのは当たり前じゃない。","ENG":"It's not your fault. Of course you'd put the students' safety first.","TWN":"這不是會長的問題，身為會長本來就應該以學生的安危為優先考量。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L3_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"아카데미에 편입한 이상 미나 양도 그 학생들 중 하나입니다.","JPN":"アカデミーに編入した以上、ミナさんもその生徒の一人です。","ENG":"But you are also one of the Academy's students now, Mina.","TWN":"既然你已經插班到我們學院，那你就也在我的考量範圍內。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"학생회장으로서 곤경에 처한 학생을 두고 물러설 수는 없어요. 저도 수색을 돕겠습니다.","JPN":"生徒会長として困っている生徒を置いて帰ることはできません。私も捜索を手伝います。","ENG":"As the Student President, I can't simply turn a blind eye to a student in need of help. I will aid your search.","TWN":"身為學生會長，怎麼可以扔下處在困境的學生不管，我也會一起幫忙找人的！"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"좋아! 그럼 시간낭비 하지 말고 바로 출발하자!","JPN":"よし！　時間がもったいないからすぐ出発するわよ！","ENG":"Great! Then let's stop wasting time and get moving!","TWN":"非常好！那我們就趕緊把握時間出發吧！"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_HATE"}}}},{"id":"L8_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"겸사겸사 테마파크를 훔쳐간 녀석도 찾아내고 말야!","JPN":"ついでにテーマパークを盗んだ奴も捜し出すの！","ENG":"We can find that jerk who stole the theme park while we're at it!","TWN":"順便把那些偷走主題樂園的傢伙也找出來！"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_HATE"}}}},{"id":"L9_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"야, 야! 난 왜 끌고 가! 우리 이렇게 친한 사이 아니었잖아?!","JPN":"ちょ、ちょっと！　ナイエル引っ張らないで！　私は生徒会長と一緒に……！","ENG":"Hey, hey! Why are you dragging me along too? We're not even that close!","TWN":"喂！你幹嘛拉我啦！跟你很熟嗎？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"응? 뭐야, 이 경보음은?","JPN":"うん？　この警報音はなに？","ENG":"Hm? What's that alarm sound?","TWN":"嗯？這個警報聲是？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"SIGMA_RAS_OPR_NULL","text":{"KOREA":"안녕, 언니들!","JPN":"ヤッホー、みんな！","ENG":"Hey, guys?","TWN":"哈囉～姊姊們！"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_OPR_NULL","face":"UNIT_LAUGH"},"R":null}},"sfx":"FX_COMBAT_ALL_MECHANIC_WORK_15"},{"id":"L15_1","type":"dialog","speaker":"SIGMA_RAS_OPR_NULL","text":{"KOREA":"함선의 레이더에 알록달록한 침식파들이 엄청 많이 나타났는데…….","JPN":"艦船のレーダーに色とりどりの侵食波がたくさん現れてね……","ENG":"There's a whole lot of colorful Corruption Rays on the radar…","TWN":"艦船的雷達偵測到超多侵蝕波的……"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_OPR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"SIGMA_RAS_OPR_NULL","text":{"KOREA":"이쪽으로 몰려온다! 무지 열심히 달리고 있나 봐!","JPN":"こっちに集まってきてるの！　すご～く一生懸命走っているみたい！","ENG":"They're all headed this way! They must be running like crazy!","TWN":"正往這裡衝過來！他們好像跑得很認真！"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_OPR_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"뭐, 예상대로네. 유미나랑 다이브를 했는데 조용할 리 없지.","JPN":"まあ、予想どおりだね。あのヤナギ・ミナとダイブをした以上、平和に終わるはずがないもの。","ENG":"Hardly surprising. Of course it's not going to be quiet when you dive with Mina.","TWN":"嗯，果然不出我所料，和劉米娜躍入後他們不可能沒有動靜。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L20_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"……무슨 뜻이야, 그거?","JPN":"……何が言いたいの？","ENG":"…What's that supposed to mean?","TWN":"……那是什麼意思？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L21_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"눈 흘길 시간에 명령이나 내려. 지금은 네가 대장이잖아.","JPN":"睨む暇があるなら指示して。今はあなたが隊長でしょ。","ENG":"Save it for later. You're the commander right now.","TWN":"有時間發問不如趕快下令吧！現在你才是隊長！"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"미나소대 임시 소대장, 유미나 씨.","JPN":"ミナ小隊の臨時小隊長、ヤナギ・ミナさん。","ENG":"Provisional Commander of the Mina Squad.","TWN":"米娜小隊臨時隊長 劉米娜！"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"너, 그건 어떻게 알고 있는 거야?!","JPN":"ちょっと、なんで知ってるの！？","ENG":"H-how did you know about that?!","TWN":"你怎麼會知道？！"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"어떻게 알고 있는지가 뭐가 중요해.","JPN":"どうして知っているかは重要じゃないよ。","ENG":"Who cares about that right now?","TWN":"我怎麼知道的不重要，"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"중요한 건 우리 미나 양이 보기보다 권력을 사랑하는 여자였다는 사실 아닐까?","JPN":"重要なのはミナさんが意外にも権力を愛する女だったという事実じゃない？","ENG":"What's important is that you're a lot more power hungry than we all thought.","TWN":"重點是，看你平時表現得很瀟灑，原來是個喜歡權力的女人！"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"그, 그런 거 아니야! 애초에 내가 지은 이름도 아니고!","JPN":"そ、そんなんじゃないよ！　そもそも私がつけた名前でもないし！","ENG":"T-that's not true! I didn't even come up with that name in the first place!","TWN":"才…才不是咧！那個隊名又不是我取的！"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"미나야! 침식체들이 몰려오고 있어!","JPN":"ミナちゃん！　侵食体が押し寄せてきてるの！","ENG":"Mina! We've got C.O.s incoming!","TWN":"米娜！侵蝕體衝過來了啦！"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"……하아.","JPN":"はあ……","ENG":"Ugh…","TWN":"……呼！"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"선배를 구출하더라도 코핀 함이 손상되면 현실세계로 돌아가지 못할 거야.","JPN":"先輩を救出してもコフィン艦が損傷してしまったら、現実世界に戻れない。","ENG":"Even if we rescue Shiyoon, we won't be able to go back if the Coffin is damaged.","TWN":"艦船如果受損就無法回到現世，那把前輩救出來也沒用！"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"우선은 전력을 다해 함선을 방어한다!","JPN":"まずは全力で艦船を防衛する！","ENG":"For now, we have to secure the ship with all we've got!","TWN":"現在，全力保護艦船！"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"네, 명령 받들겠습니다. 유미나 소대장님!","JPN":"はい、承知いたしました。ヤナギ・ミナ小隊長！","ENG":"Roger that! Commander Yoo Mina!","TWN":"是，遵命！劉米娜隊長！"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L35_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"너! 그거 하지 말라고!!","JPN":"ちょっと、それやめてくれない！？","ENG":"Hey! Cut that out, already!!","TWN":"你很故意欸！"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_LAUGH"}}}}]`);export{e as default};